Physical Examinations: {'Vital_Signs': {'Temperature': '36.8°C (98.2°F)', 'Blood_Pressure': '100/65 mmHg', 'Heart_Rate': '82 bpm', 'Respiratory_Rate': '18 breaths/min'}, 'Musculoskeletal_Examination': {'Inspection': 'No visible deformity, swelling, or bruising of the knee or hip', 'Palpation': 'Tenderness on palpation of the left hip, not knee', 'Range_of_Motion': 'Full range of motion in the knee; pain elicited with passive motion of the hip', 'Special_Tests': "Negative for anterior drawer test and McMurray's, suggesting no knee joint instability or meniscal tear"}}
Test Results: {'X-ray_Left_Hip': {'Findings': 'Flattening and fragmentation of the left femoral head consistent with Legg-Calvé-Perthes disease'}}

